1	package box2dLight.p3d;
2	
3	import com.badlogic.gdx.physics.box2d.Fixture;
4	
5	/**
6	 * Data container for linking fixtures with pseudo3d light engine
7	 * 
8	 * @author rinold
9	 */
10	public class P3dData {
11		
12		public Object userData = null;
13		
14		public float height;
15		
16		public P3dData(float h) {
17			height = h;
18		}
19		
20		public P3dData(Object data, float h) {
21			height = h;
22			userData = data;
23		}
24		
25		public float getLimit(float distance, float lightHeight, float lightRange) {
26			float l = 0f;
27			if (lightHeight > height) {
28				l = distance * height / (lightHeight - height);
29				float diff = lightRange - distance;
30				if (l > diff) l = diff;
31			} else {
32				l = lightRange - distance;
33			}
34			
35			return l > 0 ? l : 0f;
36		}
37		
38		public static Object getUserData(Fixture fixture) {
39			Object data = fixture.getUserData();
40			if (data instanceof P3dData) {
41				return ((P3dData)data).userData;
42			} else {
43				return data;
44			}
45		}
46		
47	}
