1	package box2dLight.p3d;
2	
3	import box2dLight.RayHandler;
4	import box2dLight.base.BaseLight;
5	
6	import com.badlogic.gdx.graphics.Color;
7	import com.badlogic.gdx.graphics.Mesh;
8	import com.badlogic.gdx.math.Vector2;
9	import com.badlogic.gdx.physics.box2d.Filter;
10	import com.badlogic.gdx.physics.box2d.Fixture;
11	import com.badlogic.gdx.physics.box2d.QueryCallback;
12	import com.badlogic.gdx.utils.Array;
13	import com.badlogic.gdx.utils.Disposable;
14	import com.badlogic.gdx.utils.IntArray;
15	
16	/**
17	 * Light is data container for all the light parameters. When created lights
18	 * are automatically added to rayHandler and could be removed by calling
19	 * {@link #remove()} and added manually by calling {@link #add(RayHandler)}.
20	 * 
21	 * <p>Implements {@link Disposable}
22	 * 
23	 * @author rinold
24	 */
25	public abstract class P3dLight extends BaseLight {
26	
27		protected int rayNum;
28		protected int vertexNum;
29		
30		protected float height = 0f;
31		
32		protected int activeShadows;
33		protected final Array<Mesh> dynamicShadowMeshes = new Array<Mesh>();
34		protected final Array<Fixture> affectedFixtures = new Array<Fixture>();
35		protected final Array<Vector2> tmpVerts = new Array<Vector2>();
36		
37		protected final IntArray ind = new IntArray();
38		
39		protected final Vector2 tmpStart = new Vector2();
40		protected final Vector2 tmpEnd = new Vector2();
41		protected final Vector2 tmpVec = new Vector2();
42		protected final Vector2 center = new Vector2(); 
43		
44		/**
45		 * Creates new active light and automatically adds it to the specified
46		 * {@link P3dLightManager} instance.
47		 *
48		 * @param lightManager
49		 *            not null instance of P3dLightManager
50		 * @param rays
51		 *            number of rays - more rays make light to look more realistic
52		 *            but will decrease performance, can't be less than MIN_RAYS
53		 * @param color
54		 *            light color
55		 * @param distance
56		 *            light distance (if applicable)
57		 * @param directionDegree
58		 *            direction in degrees (if applicable) 
59		 */
60		public P3dLight(P3dLightManager lightManager, int rays, Color color,
61				float distance, float directionDegree) {
62			lightManager.lightList.add(this);
63			this.lightHandler = lightManager;
64			setColor(color);
65			setDistance(distance);
66			setDirection(directionDegree);
67		}
68	
69		/**
70		 * Disposes all light resources
71		 */
72		public void dispose() {
73			super.dispose();
74			
75			for (Mesh mesh : dynamicShadowMeshes) {
76				mesh.dispose();
77			}
78			dynamicShadowMeshes.clear();
79		}
80	
81		/**
82		 * Enables/disables this light update and rendering
83		 */
84		public void setActive(boolean active) {
85			if (active == this.active)
86				return;
87	
88			this.active = active;
89			if (lightHandler == null)
90				return;
91			
92			if (active) {
93				lightHandler.lightList.add(this);
94				lightHandler.disabledLights.removeValue(this, true);
95			} else {
96				lightHandler.disabledLights.add(this);
97				lightHandler.lightList.removeValue(this, true);
98			}
99		}
100	
101		/**
102		 * @return if this light is active
103		 */
104		public boolean isActive() {
105			return active;
106		}
107	
108		public boolean getActive() {
109			return active;
110		}
111	
112		/**
113		 * Enables/disables x-ray beams for this light
114		 * 
115		 * <p>Enabling this will allow beams go through obstacles that reduce CPU
116		 * burden of light about 70%.
117		 * 
118		 * <p>Use the combination of x-ray and non x-ray lights wisely
119		 */
120		public void setXray(boolean xray) {
121			this.xray = xray;
122			if (staticLight) dirty = true;
123		}
124	
125		/**
126		 * @return if this light beams go through obstacles
127		 */
128		public boolean isXray() {
129			return xray;
130		}
131	
132		/**
133		 * Enables/disables this light static behavior
134		 * 
135		 * <p>Static light do not get any automatic updates but setting any
136		 * parameters will update it. Static lights are useful for lights that you
137		 * want to collide with static geometry but ignore all the dynamic objects
138		 * 
139		 * <p>Reduce CPU burden of light about 90%
140		 */
141		public void setStaticLight(boolean staticLight) {
142			this.staticLight = staticLight;
143			if (staticLight) dirty = true;
144		}
145	
146		/**
147		 * @return if this light is static
148		 *         <p>Static light do not get any automatic updates but setting
149		 *         any parameters will update it. Static lights are useful for
150		 *         lights that you want to collide with static geometry but ignore
151		 *         all the dynamic objects.
152		 */
153		public boolean isStaticLight() {
154			return staticLight;
155		}
156	
157		/**
158		 * @return current color of this light
159		 */
160		public Color getColor() {
161			return color;
162		}
163	
164		/**
165		 * Checks if given point is inside of this light area
166		 * 
167		 * @param x - horizontal position of point in world coordinates
168		 * @param y - vertical position of point in world coordinates
169		 */
170		public boolean contains(float x, float y) {
171			return false;
172		}
173	
174		public void setHeight(float height) {
175			this.height = height;
176		}
177	
178		public float getHeight() {
179			return this.height;
180		}
181	
182		/** Global contact filter applied to all P3d lights **/
183		static private Filter globalFilterA = null;
184		/** Per-light contact filter **/
185		private Filter filterA = null;
186	
187		/**
188		 * Sets given contact filter for this light
189		 */
190		public void setContactFilter(Filter filter) {
191			filterA = filter;
192		}
193	
194		/**
195		 * Creates a new contact filter for this light with given parameters
196		 *
197		 * @param categoryBits - see {@link Filter#categoryBits}
198		 * @param groupIndex   - see {@link Filter#groupIndex}
199		 * @param maskBits     - see {@link Filter#maskBits}
200		 */
201		public void setContactFilter(short categoryBits, short groupIndex, short maskBits) {
202			filterA = new Filter();
203			filterA.categoryBits = categoryBits;
204			filterA.groupIndex = groupIndex;
205			filterA.maskBits = maskBits;
206		}
207	
208		/**
209		 * Sets given contact filter for ALL P3d lights
210		 */
211		static public void setGlobalContactFilter(Filter filter) {
212			globalFilterA = filter;
213		}
214	
215		/**
216		 * Creates a new contact filter for ALL P3d lights with given parameters
217		 *
218		 * @param categoryBits - see {@link Filter#categoryBits}
219		 * @param groupIndex   - see {@link Filter#groupIndex}
220		 * @param maskBits     - see {@link Filter#maskBits}
221		 */
222		static public void setGlobalContactFilter(short categoryBits, short groupIndex, short maskBits) {
223			globalFilterA = new Filter();
224			globalFilterA.categoryBits = categoryBits;
225			globalFilterA.groupIndex = groupIndex;
226			globalFilterA.maskBits = maskBits;
227		}
228	
229		boolean contactFilter(Fixture fixtureB) {
230			Filter filterB = fixtureB.getFilterData();
231			if (filterA.groupIndex != 0 && filterA.groupIndex == filterB.groupIndex)
232				return filterA.groupIndex > 0;
233			return (filterA.maskBits & filterB.categoryBits) != 0 &&
234					(filterA.categoryBits & filterB.maskBits) != 0;
235		}
236	
237		boolean globalContactFilter(Fixture fixtureB) {
238			Filter filterB = fixtureB.getFilterData();
239			if (globalFilterA.groupIndex != 0 && globalFilterA.groupIndex == filterB.groupIndex)
240				return globalFilterA.groupIndex > 0;
241			return (globalFilterA.maskBits & filterB.categoryBits) != 0 &&
242					(globalFilterA.categoryBits & filterB.maskBits) != 0;
243		}
244	
245		protected boolean onDynamicCallback(Fixture fixture) {
246			if (globalFilterA != null && !globalContactFilter(fixture)) return false;
247			if (filterA != null && !contactFilter(fixture)) return false;
248			return true;
249		}
250		
251		final QueryCallback dynamicShadowCallback = new QueryCallback() {
252	
253			@Override
254			public boolean reportFixture(Fixture fixture) {
255				if (!onDynamicCallback(fixture)) return true;
256	
257				if (fixture.getUserData() instanceof P3dData) {
258					affectedFixtures.add(fixture);
259				}
260	
261				return true;
262			}
263			
264		};
265	
266	}
