2	package box2dLight.p3d;
3	
4	import com.badlogic.gdx.graphics.Color;
5	import com.badlogic.gdx.graphics.GL20;
6	import com.badlogic.gdx.graphics.Mesh;
7	import com.badlogic.gdx.graphics.Mesh.VertexDataType;
8	import com.badlogic.gdx.graphics.VertexAttribute;
9	import com.badlogic.gdx.graphics.VertexAttributes.Usage;
10	import com.badlogic.gdx.math.MathUtils;
11	import com.badlogic.gdx.math.Vector2;
12	import com.badlogic.gdx.physics.box2d.Body;
13	import com.badlogic.gdx.physics.box2d.Fixture;
14	
15	/**
16	 * Abstract base class for all positional lights
17	 * 
18	 * <p>Extends {@link P3dLight}
19	 * 
20	 * @author rinold
21	 */
22	public abstract class P3dPositionalLight extends P3dLight {
23		
24		protected final Vector2 start = new Vector2();
25		
26		protected Body body;
27		protected float bodyOffsetX;
28		protected float bodyOffsetY;
29		protected float bodyAngleOffset;
30		
31		protected float sin[];
32		protected float cos[];
33	
34		protected float endX[];
35		protected float endY[];
36	
37		/**
38		 * Creates new positional light and automatically adds it to the specified
39		 * {@link P3dLightManager} instance.
40		 *
41		 * @param lightManager
42		 *            not null instance of P3dLightManager
43		 * @param rays
44		 *            number of rays - more rays make light to look more realistic
45		 *            but will decrease performance, can't be less than MIN_RAYS
46		 * @param color
47		 *            light color
48		 * @param distance
49		 *            light distance (if applicable)
50		 * @param x
51		 *            horizontal position in world coordinates
52		 * @param y
53		 *            vertical position in world coordinates
54		 * @param directionDegree
55		 *            direction in degrees (if applicable) 
56		 */
57		public P3dPositionalLight(P3dLightManager lightManager, int rays, Color color, float distance, float x, float y, float directionDegree) {
58			super(lightManager, rays, color, distance, directionDegree);
59			start.x = x;
60			start.y = y;
61			
62			setRayNum(rays);
63	
64			lightMesh = new Mesh(
65					VertexDataType.VertexArray,
66					false, vertexNum, 0,
67					new VertexAttribute(Usage.Position, 2, "vertex_positions"),
68					new VertexAttribute(Usage.ColorPacked, 4, "quad_colors"),
69					new VertexAttribute(Usage.Generic, 1, "s"));
70			
71			setMesh();
72		}
73		
74		@Override
75		public void update() {
76			updateBody();
77			
78			if (cull()) return;
79			if (staticLight && !dirty) return;
80			
81			dirty = false;
82			
83			updateMesh();
84		}
85		
86		@Override
87		public void render() {
88			if (lightHandler.isCulling() && culled) return;
89	
90			lightHandler.lightsRenderedLastFrame++;
91			lightMesh.render(
92					shader, GL20.GL_TRIANGLE_FAN, 0, vertexNum);
93		}
94		
95		@Override
96		public void attachToBody(Body body) {
97			attachToBody(body, 0f, 0f, 0f);
98		}
99		
100		/**
101		 * Attaches light to specified body with relative offset
102		 * 
103		 * @param body
104		 *            that will be automatically followed, note that the body
105		 *            rotation angle is taken into account for the light offset
106		 *            and direction calculations
107		 * @param offsetX
108		 *            horizontal relative offset in world coordinates
109		 * @param offsetY
110		 *            vertical relative offset in world coordinates
111		 * 
112		 */
113		public void attachToBody(Body body, float offsetX, float offsetY) {
114			attachToBody(body, offsetX, offsetY, 0f);
115		}
116		
117		/**
118		 * Attaches light to specified body with relative offset and direction
119		 * 
120		 * @param body
121		 *            that will be automatically followed, note that the body
122		 *            rotation angle is taken into account for the light offset
123		 *            and direction calculations
124		 * @param offsetX
125		 *            horizontal relative offset in world coordinates
126		 * @param offSetY
127		 *            vertical relative offset in world coordinates
128		 * @param degrees
129		 *            directional relative offset in degrees
130		 */
131		public void attachToBody(Body body, float offsetX, float offSetY, float degrees) {
132			this.body = body;
133			bodyOffsetX = offsetX;
134			bodyOffsetY = offSetY;
135			bodyAngleOffset = degrees;
136			if (staticLight) dirty = true;
137		}
138	
139		@Override
140		public Vector2 getPosition() {
141			tmpPosition.x = start.x;
142			tmpPosition.y = start.y;
143			return tmpPosition;
144		}
145	
146		public Body getBody() {
147			return body;
148		}
149	
150		/** @return horizontal starting position of light in world coordinates **/
151		@Override
152		public float getX() {
153			return start.x;
154		}
155	
156		/** @return vertical starting position of light in world coordinates **/
157		@Override
158		public float getY() {
159			return start.y;
160		}
161	
162		@Override
163		public void setPosition(float x, float y) {
164			start.x = x;
165			start.y = y;
166			if (staticLight) dirty = true;
167		}
168	
169		@Override
170		public void setPosition(Vector2 position) {
171			start.x = position.x;
172			start.y = position.y;
173			if (staticLight) dirty = true;
174		}
175	
176		@Override
177		public boolean contains(float x, float y) {
178			// fast fail
179			final float x_d = start.x - x;
180			final float y_d = start.y - y;
181			final float dst2 = x_d * x_d + y_d * y_d;
182			if (distance * distance <= dst2) return false;
183	
184			// TODO: actual check
185			return true;
186		}
187		
188		protected void setRayNum(int rays) {
189			rayNum = rays;
190			vertexNum = rays + 1;
191			segments = new float[vertexNum * 8];
192			sin = new float[rays];
193			cos = new float[rays];
194			endX = new float[rays];
195			endY = new float[rays];
196		}
197		
198		protected boolean cull() {
199			culled = lightHandler.isCulling() && !lightHandler.intersect(
200						start.x, start.y, distance);
201			return culled;
202		}
203		
204		protected void updateBody() {
205			if (body == null || staticLight) return;
206			
207			final Vector2 vec = body.getPosition();
208			float angle = body.getAngle();
209			final float cos = MathUtils.cos(angle);
210			final float sin = MathUtils.sin(angle);
211			final float dX = bodyOffsetX * cos - bodyOffsetY * sin;
212			final float dY = bodyOffsetX * sin + bodyOffsetY * cos;
213			start.x = vec.x + dX;
214			start.y = vec.y + dY;
215			setDirection(bodyAngleOffset + angle * MathUtils.radiansToDegrees);
216		}
217		
218		protected void updateMesh() {
219			setMesh();
220		}
221		
222		protected void prepeareFixtureData() {
223			affectedFixtures.clear();
224			lightHandler.getWorld().QueryAABB(
225					dynamicShadowCallback,
226					start.x - distance, start.y - distance,
227					start.x + distance, start.y + distance);
228		}
229	
230		protected void setMesh() {
231			// ray starting point
232			int size = 0;
233			float colorF = color.cpy().mul(1f / P3dLightManager.colorReduction).toFloatBits();
234	
235			segments[size++] = start.x;
236			segments[size++] = start.y;
237			segments[size++] = colorF;
238			segments[size++] = 1f;
239			// rays ending points.
240			for (int i = 0; i < rayNum; i++) {
241				segments[size++] = start.x + endX[i];
242				segments[size++] = start.y + endY[i];
243				segments[size++] = colorF;
244				segments[size++] = 0f;
245			}
246			lightMesh.setVertices(segments, 0, size);
247		}
248		
249		@Override
250		protected boolean onDynamicCallback(Fixture fixture) {
251			if (!super.onDynamicCallback(fixture)) return false;
252			return fixture.getBody() != body;
253		}
254		
255	}
