1	package box2dLight.p3d;
2	
3	import com.badlogic.gdx.graphics.Color;
4	import com.badlogic.gdx.graphics.GL20;
5	import com.badlogic.gdx.graphics.Mesh;
6	import com.badlogic.gdx.graphics.Mesh.VertexDataType;
7	import com.badlogic.gdx.graphics.VertexAttribute;
8	import com.badlogic.gdx.graphics.VertexAttributes.Usage;
9	import com.badlogic.gdx.math.Intersector;
10	import com.badlogic.gdx.math.MathUtils;
11	import com.badlogic.gdx.physics.box2d.Body;
12	import com.badlogic.gdx.physics.box2d.ChainShape;
13	import com.badlogic.gdx.physics.box2d.CircleShape;
14	import com.badlogic.gdx.physics.box2d.EdgeShape;
15	import com.badlogic.gdx.physics.box2d.Fixture;
16	import com.badlogic.gdx.physics.box2d.PolygonShape;
17	import com.badlogic.gdx.physics.box2d.Shape;
18	import com.badlogic.gdx.physics.box2d.Shape.Type;
19	
20	/**
21	 * Light shaped as a circle's sector with given radius, direction and angle,
22	 * with pseudo-3D height-based shadow support.
23	 *
24	 * <p>Extends {@link P3dPositionalLight}
25	 *
26	 * @author rinold
27	 */
28	public class P3dConeLight extends P3dPositionalLight {
29	
30		protected float coneDegree;
31	
32		/**
33		 * Creates light shaped as a circle's sector with given radius, direction and arc angle
34		 *
35		 * @param lightManager
36		 *            not {@code null} instance of P3dLightManager
37		 * @param rays
38		 *            number of rays - more rays make light to look more realistic
39		 *            but will decrease performance, can't be less than MIN_RAYS
40		 * @param color
41		 *            color, set to {@code null} to use the default color
42		 * @param distance
43		 *            distance of cone light
44		 * @param x
45		 *            horizontal position in world coordinates
46		 * @param y
47		 *            vertical position in world coordinates
48		 * @param directionDegree
49		 *            direction of cone light in degrees
50		 * @param coneDegree
51		 *            half-size of cone light, centered over direction (clamped 0-180)
52		 */
53		public P3dConeLight(P3dLightManager lightManager, int rays, Color color,
54				float distance, float x, float y, float directionDegree,
55				float coneDegree) {
56			super(lightManager, rays, color, distance, x, y, directionDegree);
57			setConeDegree(coneDegree);
58		}
59	
60		@Override
61		public void update() {
62			updateBody();
63			if (dirty) {
64				setEndPoints();
65			}
66	
67			if (cull()) return;
68			if (staticLight && !dirty) return;
69	
70			dirty = false;
71			updateMesh();
72			prepeareFixtureData();
73			updateDynamicShadowMeshes();
74		}
75	
76		@Override
77		public void dynamicShadowRender() {
78			for (int i = 0; i < activeShadows; i++) {
79				Mesh m = dynamicShadowMeshes.get(i);
80				m.render(shader, GL20.GL_TRIANGLE_STRIP);
81			}
82		}
83	
84		/**
85		 * Sets light direction
86		 * <p>Actual recalculations will be done only on {@link #update()} call
87		 */
88		@Override
89		public void setDirection(float directionDegree) {
90			direction = directionDegree;
91			dirty = true;
92		}
93	
94		public float getDirection() {
95			return direction;
96		}
97	
98		/**
99		 * @return this light's cone degree (half-angle)
100		 */
101		public float getConeDegree() {
102			return coneDegree;
103		}
104	
105		/**
106		 * Sets the half-angle of the cone arc.
107		 *
108		 * <p>Arc angle = coneDegree * 2, centered over direction angle
109		 * <p>Actual recalculations will be done only on {@link #update()} call
110		 */
111		public void setConeDegree(float coneDegree) {
112			this.coneDegree = MathUtils.clamp(coneDegree, 0f, 180f);
113			dirty = true;
114		}
115	
116		/**
117		 * Sets light distance
118		 *
119		 * <p>MIN value capped to 0.01f meter
120		 * <p>Actual recalculations will be done only on {@link #update()} call
121		 */
122		@Override
123		public void setDistance(float dist) {
124			dist *= gammaCorrectionValue;
125			this.distance = dist < 0.01f ? 0.01f : dist;
126			dirty = true;
127		}
128	
129		/** Updates light sector based on distance, direction and coneDegree **/
130		protected void setEndPoints() {
131			for (int i = 0; i < rayNum; i++) {
132				float angle = direction + coneDegree - 2f * coneDegree * i / (rayNum - 1f);
133				sin[i] = MathUtils.sinDeg(angle);
134				cos[i] = MathUtils.cosDeg(angle);
135				endX[i] = distance * cos[i];
136				endY[i] = distance * sin[i];
137			}
138		}
139	
140		protected void updateDynamicShadowMeshes() {
141			activeShadows = 0;
142			for (Fixture fixture : affectedFixtures) {
143				P3dData data = (P3dData) fixture.getUserData();
144				if (data == null || fixture.isSensor()) continue;
145	
146				int size = 0;
147				float l = 0f;
148	
149				Shape fixtureShape = fixture.getShape();
150				Type type = fixtureShape.getType();
151				Body body = fixture.getBody();
152				center.set(body.getWorldCenter());
153	
154				if (type == Type.Polygon || type == Type.Chain) {
155					boolean isPolygon = (type == Type.Polygon);
156					ChainShape cShape = isPolygon ? null : (ChainShape) fixtureShape;
157					PolygonShape pShape = isPolygon ? (PolygonShape) fixtureShape : null;
158					int vertexCount = isPolygon ? pShape.getVertexCount() : cShape.getVertexCount();
159					int minN = -1;
160					int maxN = -1;
161					int minDstN = -1;
162					float minDst = Float.POSITIVE_INFINITY;
163					boolean hasGasp = false;
164					tmpVerts.clear();
165					for (int n = 0; n < vertexCount; n++) {
166						if (isPolygon) {
167							pShape.getVertex(n, tmpVec);
168						} else {
169							cShape.getVertex(n, tmpVec);
170						}
171						tmpVec.set(body.getWorldPoint(tmpVec));
172						tmpVerts.add(tmpVec.cpy());
173						tmpEnd.set(tmpVec).sub(start).limit2(0.0001f).add(tmpVec);
174						if (fixture.testPoint(tmpEnd)) {
175							if (minN == -1) minN = n;
176							maxN = n;
177							hasGasp = true;
178							continue;
179						}
180	
181						float currDist = tmpVec.dst2(start);
182						if (currDist < minDst) {
183							minDst = currDist;
184							minDstN = n;
185						}
186					}
187	
188					ind.clear();
189					if (!hasGasp) {
190						tmpVec.set(tmpVerts.get(minDstN));
191						for (int n = minDstN; n < vertexCount; n++) {
192							ind.add(n);
193						}
194						for (int n = 0; n < minDstN; n++) {
195							ind.add(n);
196						}
197						if (Intersector.pointLineSide(start, center, tmpVec) > 0) {
198							ind.reverse();
199							ind.insert(0, ind.pop());
200						}
201					} else if (minN == 0 && maxN == vertexCount - 1) {
202						for (int n = maxN - 1; n > minN; n--) {
203							ind.add(n);
204						}
205					} else {
206						for (int n = minN - 1; n > -1; n--) {
207							ind.add(n);
208						}
209						for (int n = vertexCount - 1; n > maxN; n--) {
210							ind.add(n);
211						}
212					}
213	
214					for (int n : ind.toArray()) {
215						tmpVec.set(tmpVerts.get(n));
216	
217						float dst = tmpVec.dst(start);
218						l = data.getLimit(dst, height, distance);
219						tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
220						float f1 = 1f - dst / distance;
221						float f2 = 1f - (dst + l) / distance;
222	
223						segments[size++] = tmpVec.x;
224						segments[size++] = tmpVec.y;
