231						segments[size++] = f2;
232					}
233				} else if (type == Type.Circle) {
234					CircleShape shape = (CircleShape) fixtureShape;
235					float r = shape.getRadius();
236					float dst = tmpVec.set(center).dst(start);
237					float a = (float) Math.acos(r / dst);
238					l = data.getLimit(dst, height, distance);
239					float f1 = 1f - dst / distance;
240					float f2 = 1f - (dst + l) / distance;
241	
242					tmpVec.set(start).sub(center).clamp(r, r).rotateRad(a);
243					tmpStart.set(center).add(tmpVec);
244	
245					float angle = (MathUtils.PI2 - 2f * a) /
246							P3dLightManager.CIRCLE_APPROX_POINTS;
247					for (int k = 0; k < P3dLightManager.CIRCLE_APPROX_POINTS; k++) {
248						tmpStart.set(center).add(tmpVec);
249						segments[size++] = tmpStart.x;
250						segments[size++] = tmpStart.y;
251						segments[size++] = colorF;
252						segments[size++] = f1;
253	
254						tmpEnd.set(tmpStart).sub(start).setLength(l).add(tmpStart);
255						segments[size++] = tmpEnd.x;
256						segments[size++] = tmpEnd.y;
257						segments[size++] = colorF;
258						segments[size++] = f2;
259	
260						tmpVec.rotateRad(angle);
261					}
262				} else if (type == Type.Edge) {
263					EdgeShape shape = (EdgeShape) fixtureShape;
264	
265					shape.getVertex1(tmpVec);
266					tmpVec.set(body.getWorldPoint(tmpVec));
267					float dst = tmpVec.dst(start);
268					l = data.getLimit(dst, height, distance);
269					float f1 = 1f - dst / distance;
270					float f2 = 1f - (dst + l) / distance;
271	
272					segments[size++] = tmpVec.x;
273					segments[size++] = tmpVec.y;
274					segments[size++] = colorF;
275					segments[size++] = f1;
276	
277					tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
278					segments[size++] = tmpEnd.x;
279					segments[size++] = tmpEnd.y;
280					segments[size++] = colorF;
281					segments[size++] = f2;
282	
283					shape.getVertex2(tmpVec);
284					tmpVec.set(body.getWorldPoint(tmpVec));
285					dst = tmpVec.dst(start);
286					l = data.getLimit(dst, height, distance);
287					f1 = 1f - dst / distance;
288					f2 = 1f - (dst + l) / distance;
289	
290					segments[size++] = tmpVec.x;
291					segments[size++] = tmpVec.y;
292					segments[size++] = colorF;
293					segments[size++] = f1;
294	
295					tmpEnd.set(tmpVec).sub(start).setLength(l).add(tmpVec);
296					segments[size++] = tmpEnd.x;
297					segments[size++] = tmpEnd.y;
298					segments[size++] = colorF;
299					segments[size++] = f2;
300				}
301	
302				Mesh mesh;
303				if (activeShadows >= dynamicShadowMeshes.size) {
304					mesh = new Mesh(
305							VertexDataType.VertexArray, false,
306							P3dLightManager.MAX_SHADOW_VERTICES, 0,
