142					lightHandler.x1, lightHandler.y1,
143					lightHandler.x2, lightHandler.y2);
144		}
145		
146		protected void updateDynamicShadowMeshes() {
147			activeShadows = 0;
148			for (Fixture fixture : affectedFixtures) {
149				P3dData data = (P3dData)fixture.getUserData();
150				if (data == null || fixture.isSensor()) continue;
151				
152				Shape fixtureShape = fixture.getShape();
153				Type type = fixtureShape.getType();
154				Body body = fixture.getBody();
155				center.set(body.getWorldCenter());
156				lstart.set(center).add(xDisp, yDisp);
157				
158				int size = 0;
159				float l = data.height /
160						(float) Math.tan(height * MathUtils.degRad);
161				if (type == Type.Polygon || type == Type.Chain) {
162					boolean isPolygon = (type == Type.Polygon);
163					ChainShape cShape = isPolygon ?
164							null : (ChainShape)fixtureShape;
165					PolygonShape pShape = isPolygon ?
166							(PolygonShape)fixtureShape : null;
167					int vertexCount = isPolygon ?
168							pShape.getVertexCount() : cShape.getVertexCount();
169					int minN = -1;
170					int maxN = -1;
171					int minDstN = -1;
172					float minDst = Float.POSITIVE_INFINITY;
173					boolean hasGasp = false;
174					tmpVerts.clear();
175					for (int n = 0; n < vertexCount; n++) {
176						if (isPolygon) {
177							pShape.getVertex(n, tmpVec);
178						} else {
179							cShape.getVertex(n, tmpVec);
180						}
181						tmpVec.set(body.getWorldPoint(tmpVec));
182						tmpVerts.add(tmpVec.cpy());
183						
184						tmpEnd.set(tmpVec).sub(lstart).limit2(0.0001f).add(tmpVec);
185						if (fixture.testPoint(tmpEnd)) {
186							if (minN == -1) minN = n;
187							maxN = n;
188							hasGasp = true;
189							continue;
190						}
191						float currDist = tmpVec.dst2(lstart);
192						if (currDist < minDst) {
193							minDst = currDist;
194							minDstN = n;
195						}
196					}
197					
198					ind.clear();
199					if (!hasGasp) {
200						tmpVec.set(tmpVerts.get(minDstN));
201						for (int n = minDstN; n < vertexCount; n++) {
202							ind.add(n);
203						}
204						for (int n = 0; n < minDstN; n++) {
205							ind.add(n);
206						}
207						if (Intersector.pointLineSide(lstart, center, tmpVec) > 0) {
208							int z = ind.get(0);
209							ind.removeIndex(0);
210							ind.reverse();
211							ind.insert(0, z);
212						}
213					} else if (minN == 0 && maxN == vertexCount - 1) {
214						for (int n = maxN - 1; n > minN; n--) {
215							ind.add(n);
216						}
217					} else {
218						for (int n = minN - 1; n > -1; n--) {
219							ind.add(n);
220						}
221						for (int n = vertexCount - 1; n > maxN ; n--) {
222							ind.add(n);
223						}
224					}
225					
226					for (int n : ind.toArray()) {
227						tmpVec.set(tmpVerts.get(n));
228						tmpEnd.set(tmpVec).sub(lstart).setLength(l).add(tmpVec);
229						
230						segments[size++] = tmpVec.x;
231						segments[size++] = tmpVec.y;
232						segments[size++] = colorF;
233						segments[size++] = 1f;
234						
235						segments[size++] = tmpEnd.x;
236						segments[size++] = tmpEnd.y;
237						segments[size++] = colorF;
238						segments[size++] = 1f;
239					}
240				} else if (type == Type.Circle) {
241					CircleShape shape = (CircleShape)fixtureShape;
242					
243					float r = shape.getRadius();
244					float dst = tmpVec.set(center).dst(lstart);
245					float a = (float) Math.acos(r/dst);
246					//l = data.getLimit(dst, height, distance);
247					//float f1 = 1f - dst / distance;
248					//float f2 = 1f - (dst + l) / distance;
249					
250					tmpVec.set(lstart).sub(center).clamp(r, r).rotateRad(a);
251					tmpStart.set(center).add(tmpVec);
252					
253					float angle = (MathUtils.PI2 - 2f * a) /
254							P3dLightManager.CIRCLE_APPROX_POINTS;
255					for (int k = 0; k < P3dLightManager.CIRCLE_APPROX_POINTS; k++) {
256						tmpStart.set(center).add(tmpVec);
257						segments[size++] = tmpStart.x;
258						segments[size++] = tmpStart.y;
259						segments[size++] = colorF;
260						segments[size++] = 1f;
261						
262						tmpEnd.set(tmpStart).sub(lstart).setLength(l).add(tmpStart);
263						segments[size++] = tmpEnd.x;
264						segments[size++] = tmpEnd.y;
265						segments[size++] = colorF;
266						segments[size++] = 1f;
267						
268						tmpVec.rotateRad(angle);
269					}
270				} else if (type == Type.Edge) {
271					EdgeShape shape = (EdgeShape)fixtureShape;
272					
273					shape.getVertex1(tmpVec);
274					tmpVec.set(body.getWorldPoint(tmpVec));
275					
276					segments[size++] = tmpVec.x;
277					segments[size++] = tmpVec.y;
278					segments[size++] = colorF;
279					segments[size++] = 1f;
280					
281					tmpEnd.set(tmpVec).sub(lstart).setLength(l).add(tmpVec);
282					segments[size++] = tmpEnd.x;
283					segments[size++] = tmpEnd.y;
284					segments[size++] = colorF;
285					segments[size++] = 1f;
286					
287					shape.getVertex2(tmpVec);
288					tmpVec.set(body.getWorldPoint(tmpVec));
289					segments[size++] = tmpVec.x;
290					segments[size++] = tmpVec.y;
291					segments[size++] = colorF;
292					segments[size++] = 1f;
293					
294					tmpEnd.set(tmpVec).sub(lstart).setLength(l).add(tmpVec);
295					segments[size++] = tmpEnd.x;
296					segments[size++] = tmpEnd.y;
297					segments[size++] = colorF;
298					segments[size++] = 1f;
299				}		
300				
301				Mesh mesh = null;
302				if (activeShadows >= dynamicShadowMeshes.size) {
303					mesh = new Mesh(
304							VertexDataType.VertexArray, false,
305							P3dLightManager.MAX_SHADOW_VERTICES, 0,
306							new VertexAttribute(Usage.Position, 2, "vertex_positions"),
307							new VertexAttribute(Usage.ColorPacked, 4, "quad_colors"),
308							new VertexAttribute(Usage.Generic, 1, "s"));
309					dynamicShadowMeshes.add(mesh);
310				} else {
311					mesh = dynamicShadowMeshes.get(activeShadows);
312				}
313				mesh.setVertices(segments, 0, size);
314				activeShadows++;
315			}
316			Gdx.app.log("P3dDirectionalLight >>>", "activeShadows="+activeShadows);
317		}
318		
