13	/**
14	 * Light map for pseudo-3d rendering
15	 * 
16	 * @author rinold
17	 */
18	class P3dLightMap extends BaseLightMap {
19		
20		P3dLightManager lightManager;
21	
22		FrameBuffer shadowBuffer;
23		ShaderProgram shadowShader;
24	
25		public void render() {
26	
27			boolean needed = lightManager.getLigtsRenderedLastFrame() > 0;
28			if (needed && lightManager.isBlur()) {
29				gaussianBlur(frameBuffer, lightManager.getBlurNum());
30				gaussianBlur(shadowBuffer, lightManager.shadowBlurPasses);
31			}
32	
33			if (lightMapDrawingDisabled)
34				return;
35			
36			frameBuffer.getColorBufferTexture().bind(1);
37			shadowBuffer.getColorBufferTexture().bind(0);
38	
39			final Color c = lightHandler.getAmbientLight();
40			shadowShader.begin();
41			{
42				lightHandler.diffuseBlendFunc.apply();
43				shadowShader.setUniformf("ambient", c.r, c.g, c.b, c.a);
44				shadowShader.setUniformi("u_texture", 1);
45				shadowShader.setUniformi("u_shadows", 0);
46				lightMapMesh.render(shadowShader, GL20.GL_TRIANGLE_FAN);
47			}
48			shadowShader.end();
49			
50			Gdx.gl20.glDisable(GL20.GL_BLEND);
51		}
