53		public P3dLightMap(P3dLightManager manager, int fboWidth, int fboHeight) {
54			super(manager, fboWidth, fboHeight);
55			lightManager = manager;
56			
57			shadowShader = DynamicShadowShader.createShadowShader(P3dLightManager.colorReduction);
58			shadowBuffer = new FrameBuffer(Format.RGBA8888, fboWidth,
59					fboHeight, false);
60		}
61	
62		public void dispose() {
63			super.dispose();
64			shadowBuffer.dispose();
65			shadowShader.dispose();
66		}
