9	import com.badlogic.gdx.physics.box2d.World;
10	
11	/**
12	 * Handler that manages everything related to lights updating and rendering
13	 * 
14	 * @author rinold
15	 */
16	public class P3dLightManager extends BaseLightHandler {
17	
18		protected final P3dLightMap lightMap;
19	
20		/** TODO: This could be made adaptive to ratio of camera sizes * zoom
21		 * vs the CircleShape radius - thus will provide smooth radial shadows
22		 * while resizing and zooming in and out */
23		protected static int CIRCLE_APPROX_POINTS = 32;
24		
25		protected static int MAX_SHADOW_VERTICES = 64;
26		
27		protected static int colorReduction = 3;
28		
29		protected int shadowBlurPasses = 1;
30		
31		/**
32		 * Class constructor specifying the physics world from where collision
33		 * geometry is taken.
34		 * 
35		 * <p>NOTE: FBO size is 1/4 * screen size and used by default.
36		 * 
37		 * <p>Default settings are:
38		 * <ul>
39		 *     <li>culling = true
40		 *     <li>shadows = true
41		 *     <li>diffuse = false
42		 *     <li>blur = true
43		 *     <li>blurNum = 1
44		 *     <li>ambientLight = 0f
45		 * </ul>
46		 *
47		 * @see #P3dLightManager(World, int, int)
48		 */
49		public P3dLightManager(World world) {
50			this(world, Gdx.graphics.getWidth() / 4, Gdx.graphics
51					.getHeight() / 4);
52		}
53	
54		/**
55		 * Class constructor specifying the physics world from where collision
56		 * geometry is taken, and size of FBO used for intermediate rendering.
57		 * 
58		 * @see #P3dLightManager(World)
59		 */
60		public P3dLightManager(World world, int fboWidth, int fboHeigth) {
61			super(world);
62			lightMap = new P3dLightMap(this, fboWidth, fboHeigth);
63		}
64		
65		/**
66		 * Manual rendering method for all lights.
67		 * 
68		 * <p><b>NOTE!</b> Remember to set combined matrix and update lights
69		 * before using this method manually.
70		 * 
71		 * <p>Don't call this inside of any begin/end statements.
72		 * Call this method after you have rendered background but before UI.
73		 * Box2d bodies can be rendered before or after depending how you want
74		 * the x-ray lights to interact with them.
75		 * 
76		 * @see #updateAndRender()
77		 * @see #update()
78		 * @see #setCombinedMatrix(Matrix4)
79		 * @see #setCombinedMatrix(Matrix4, float, float, float, float)
80		 */
81		public void render() {
82			lightsRenderedLastFrame = 0;
83	
84			Gdx.gl.glDepthMask(false);
85			Gdx.gl.glEnable(GL20.GL_BLEND);
86	
87			lightMap.frameBuffer.begin();
88			Gdx.gl.glClearColor(0f, 0f, 0f, 0f);
89			Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);
90	
91			simpleBlendFunc.apply();
92			lightShader.begin();
93			{
94				lightShader.setUniformMatrix("u_projTrans", combined);
95				for (BaseLight light : lightList) {
96					light.render();
97				}
98			}
99			lightShader.end();
100			
101			if (customViewport) {
102				lightMap.frameBuffer.end(
103					viewportX,
104					viewportY,
105					viewportWidth,
106					viewportHeight);
107			} else {
108				lightMap.frameBuffer.end();
109			}
110			
111			lightMap.shadowBuffer.begin();
112			Gdx.gl.glClearColor(0f, 0f, 0f, 0f);
113			Gdx.gl.glClear(GL20.GL_COLOR_BUFFER_BIT);
114			
115			lightShader.begin();
116			{
117				for (BaseLight light : lightList) {
118					light.dynamicShadowRender();
119				}
120			}
121			lightShader.end();
122			
123			if (customViewport) {
124				lightMap.shadowBuffer.end(
125					viewportX,
126					viewportY,
127					viewportWidth,
128					viewportHeight);
129			} else {
130				lightMap.shadowBuffer.end();
131			}
132			
133			lightMap.render();
134		}
135		
136		public void setBlurNum(int num) {
137			lightBlurPasses = shadowBlurPasses = num;
138		}
139		
140	}
