4	import com.badlogic.gdx.math.MathUtils;
5	
6	/**
7	 * Light shaped as a circle's sector with given radius, direction and angle
8	 * 
9	 * <p>Extends {@link PositionalLight}
10	 * 
11	 * @author kalle_h
12	 */
13	public class ConeLight extends PositionalLight {
14	
15		float coneDegree;
16	
17		/**
18		 * Creates light shaped as a circle's sector with given radius, direction and arc angle
19		 * 
20		 * @param rayHandler
21		 *            not {@code null} instance of RayHandler
22		 * @param rays
23		 *            number of rays - more rays make light to look more realistic
24		 *            but will decrease performance, can't be less than MIN_RAYS
25		 * @param color
26		 *            color, set to {@code null} to use the default color
27		 * @param distance
28		 *            distance of cone light, soft shadow length is set to distance * 0.1f
29		 * @param x
30		 *            axis position
31		 * @param y
32		 *            axis position
33		 * @param directionDegree
34		 *            direction of cone light
35		 * @param coneDegree
36		 *            half-size of cone light, centered over direction
37		 */
38		public ConeLight(RayHandler rayHandler, int rays, Color color,
39				float distance, float x, float y, float directionDegree,
40				float coneDegree) {
41	
42			super(rayHandler, rays, color, distance, x, y, directionDegree);
43			setConeDegree(coneDegree);
44		}
45		
46		@Override
47		public void update() {
48			if (rayHandler.pseudo3d) {
49				prepareFixtureData();
50				updateDynamicShadowMeshes();
51			}
52	
53			updateBody();
54			if (dirty) setEndPoints();
55			
56			if (cull()) return;
57			if (staticLight && !dirty) return;
58			
59			dirty = false;
60			updateMesh();
61		}
62	
63		/**
64		 * Sets light direction
65		 * <p>Actual recalculations will be done only on {@link #update()} call
66		 */
67		public void setDirection(float direction) {
68			this.direction = direction;
69			dirty = true;
70		}
71	
72		/**
73		 * @return this lights cone degree
74		 */
75		public float getConeDegree() {
76			return coneDegree;
77		}
78	
79		/**
80		 * How big is the arc of cone
81		 * 
82		 * <p>Arc angle = coneDegree * 2, centered over direction angle
83		 * <p>Actual recalculations will be done only on {@link #update()} call
84		 * 
85		 */
86		public void setConeDegree(float coneDegree) {
87			this.coneDegree = MathUtils.clamp(coneDegree, 0f, 180f);
88			dirty = true;
89		}
90	
91		/**
92		 * Sets light distance
93		 * 
94		 * <p>MIN value capped to 0.1f meter
95		 * <p>Actual recalculations will be done only on {@link #update()} call
96		 */
97		public void setDistance(float dist) {
98			dist *= gammaCorrectionValue;
99			this.distance = dist < 0.01f ? 0.01f : dist;
100			dirty = true;
101		}
102		
103		/** Updates lights sector basing on distance, direction and coneDegree **/
104		protected void setEndPoints() {
105			for (int i = 0; i < rayNum; i++) {
106				float angle = direction + coneDegree - 2f * coneDegree * i
107						/ (rayNum - 1f);
108				final float s = sin[i] = MathUtils.sinDeg(angle);
109				final float c = cos[i] = MathUtils.cosDeg(angle);
110				endX[i] = distance * c;
111				endY[i] = distance * s;
112			}
113		}
114	
115	}
