188		public boolean contains(float x, float y) {
189			// fast fail
190			final float x_d = start.x - x;
191			final float y_d = start.y - y;
192			final float dst2 = x_d * x_d + y_d * y_d;
193			if (distance * distance <= dst2) return false;
194	
195			// actual check
196			boolean oddNodes = false;
197			float x2 = mx[rayNum] = start.x;
198			float y2 = my[rayNum] = start.y;
199			float x1, y1;
200			for (int i = 0; i <= rayNum; x2 = x1, y2 = y1, ++i) {
201				x1 = mx[i];
202				y1 = my[i];
203				if (((y1 < y) && (y2 >= y)) || (y1 >= y) && (y2 < y)) {
204					if ((y - y1) / (y2 - y1) * (x2 - x1) < (x - x1)) oddNodes = !oddNodes;
205				}
206			}
207			return oddNodes;
208		}
